/**
 * T6: M6-Frontend-Infra — TypeScript Types Tests
 *
 * Tests that the type definitions in src/types/task.ts exist and are correctly shaped.
 * Covers: Priority enum, TaskStatus enum, Task interface, PageResponse interface, CreateTaskRequest interface.
 *
 * These tests will fail until the implementation file is created.
 */
import { describe, it, expect } from 'vitest'
import {
  Priority,
  TaskStatus,
  type Task,
  type PageResponse,
  type CreateTaskRequest,
} from '@/types/task'

describe('Priority enum', () => {
  it('should have HIGH, MEDIUM, LOW values', () => {
    expect(Priority.HIGH).toBe('HIGH')
    expect(Priority.MEDIUM).toBe('MEDIUM')
    expect(Priority.LOW).toBe('LOW')
  })

  it('should have exactly 3 members', () => {
    const values = Object.values(Priority)
    expect(values).toHaveLength(3)
  })
})

describe('TaskStatus enum', () => {
  it('should have TODO, IN_PROGRESS, DONE, CLOSED values', () => {
    expect(TaskStatus.TODO).toBe('TODO')
    expect(TaskStatus.IN_PROGRESS).toBe('IN_PROGRESS')
    expect(TaskStatus.DONE).toBe('DONE')
    expect(TaskStatus.CLOSED).toBe('CLOSED')
  })

  it('should have exactly 4 members', () => {
    const values = Object.values(TaskStatus)
    expect(values).toHaveLength(4)
  })
})

describe('Task interface', () => {
  it('should allow creating a valid Task object', () => {
    const task: Task = {
      id: 1,
      title: 'Test Task',
      description: 'A description',
      priority: Priority.MEDIUM,
      status: TaskStatus.TODO,
      createdBy: 42,
      createdAt: '2026-03-06T10:00:00',
      updatedAt: null,
    }

    expect(task.id).toBe(1)
    expect(task.title).toBe('Test Task')
    expect(task.description).toBe('A description')
    expect(task.priority).toBe(Priority.MEDIUM)
    expect(task.status).toBe(TaskStatus.TODO)
    expect(task.createdBy).toBe(42)
    expect(task.createdAt).toBe('2026-03-06T10:00:00')
    expect(task.updatedAt).toBeNull()
  })

  it('should allow updatedAt to be a string when present', () => {
    const task: Task = {
      id: 2,
      title: 'Updated Task',
      description: '',
      priority: Priority.HIGH,
      status: TaskStatus.IN_PROGRESS,
      createdBy: 1,
      createdAt: '2026-03-06T10:00:00',
      updatedAt: '2026-03-06T12:00:00',
    }

    expect(task.updatedAt).toBe('2026-03-06T12:00:00')
  })
})

describe('PageResponse interface', () => {
  it('should allow creating a valid PageResponse object', () => {
    const page: PageResponse<Task> = {
      content: [],
      page: 0,
      size: 20,
      totalElements: 0,
      totalPages: 0,
    }

    expect(page.content).toEqual([])
    expect(page.page).toBe(0)
    expect(page.size).toBe(20)
    expect(page.totalElements).toBe(0)
    expect(page.totalPages).toBe(0)
  })

  it('should hold Task items in content array', () => {
    const task: Task = {
      id: 1,
      title: 'Task',
      description: null,
      priority: Priority.LOW,
      status: TaskStatus.DONE,
      createdBy: 1,
      createdAt: '2026-03-06T10:00:00',
      updatedAt: null,
    }

    const page: PageResponse<Task> = {
      content: [task],
      page: 0,
      size: 20,
      totalElements: 1,
      totalPages: 1,
    }

    expect(page.content).toHaveLength(1)
    expect(page.content[0].title).toBe('Task')
  })
})

describe('CreateTaskRequest interface', () => {
  it('should allow creating a request with required fields only', () => {
    const req: CreateTaskRequest = {
      title: 'New Task',
    }

    expect(req.title).toBe('New Task')
    expect(req.description).toBeUndefined()
    expect(req.priority).toBeUndefined()
  })

  it('should allow creating a request with all fields', () => {
    const req: CreateTaskRequest = {
      title: 'New Task',
      description: 'Some description',
      priority: Priority.HIGH,
    }

    expect(req.title).toBe('New Task')
    expect(req.description).toBe('Some description')
    expect(req.priority).toBe(Priority.HIGH)
  })
})

/**
 * T6: M6-Frontend-Infra — API Service Tests
 *
 * Tests for src/api/taskApi.ts:
 * - axios instance creation with JWT interceptor
 * - fetchTasks sends correct query params
 * - createTask sends correct POST body
 * - getTask sends correct GET request
 * - Authorization header injection from localStorage token
 *
 * These tests will fail until the implementation file is created.
 */
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import axios from 'axios'

// We mock axios so we can intercept calls without a real server
vi.mock('axios', async () => {
  const mockAxiosInstance = {
    get: vi.fn(),
    post: vi.fn(),
    put: vi.fn(),
    delete: vi.fn(),
    patch: vi.fn(),
    interceptors: {
      request: {
        use: vi.fn(),
      },
      response: {
        use: vi.fn(),
      },
    },
    defaults: {
      headers: {
        common: {},
      },
    },
  }

  return {
    default: {
      create: vi.fn(() => mockAxiosInstance),
    },
    __mockInstance: mockAxiosInstance,
  }
})

// Helper to get the mock instance
function getMockAxiosInstance() {
  return (axios as any).__mockInstance
}

describe('taskApi module', () => {
  let taskApi: typeof import('@/api/taskApi')

  beforeEach(async () => {
    vi.resetModules()
    // Clear any stored token
    localStorage.clear()
  })

  afterEach(() => {
    vi.restoreAllMocks()
  })

  it('should create an axios instance', async () => {
    taskApi = await import('@/api/taskApi')
    expect(axios.create).toHaveBeenCalled()
  })

  it('should register a request interceptor for JWT auth', async () => {
    taskApi = await import('@/api/taskApi')
    const mockInstance = getMockAxiosInstance()
    expect(mockInstance.interceptors.request.use).toHaveBeenCalled()
  })

  describe('JWT interceptor', () => {
    it('should add Authorization header when token exists in localStorage', async () => {
      localStorage.setItem('token', 'test-jwt-token')
      taskApi = await import('@/api/taskApi')

      const mockInstance = getMockAxiosInstance()
      // Get the interceptor function that was registered
      const interceptorFn = mockInstance.interceptors.request.use.mock.calls[0][0]

      const config = { headers: {} as Record<string, string> }
      const result = interceptorFn(config)

      expect(result.headers['Authorization'] || result.headers?.Authorization).toBe(
        'Bearer test-jwt-token'
      )
    })

    it('should not add Authorization header when no token exists', async () => {
      localStorage.removeItem('token')
      taskApi = await import('@/api/taskApi')

      const mockInstance = getMockAxiosInstance()
      const interceptorFn = mockInstance.interceptors.request.use.mock.calls[0][0]

      const config = { headers: {} as Record<string, string> }
      const result = interceptorFn(config)

      expect(result.headers['Authorization']).toBeUndefined()
    })
  })

  describe('fetchTasks', () => {
    it('should call GET with correct query params (page, size, keyword, priority, status)', async () => {
      taskApi = await import('@/api/taskApi')
      const mockInstance = getMockAxiosInstance()
      mockInstance.get.mockResolvedValueOnce({
        data: {
          content: [],
          page: 0,
          size: 20,
          totalElements: 0,
          totalPages: 0,
        },
      })

      await taskApi.fetchTasks({
        page: 1,
        size: 20,
        keyword: 'test',
        priority: 'HIGH',
        status: 'TODO',
      })

      expect(mockInstance.get).toHaveBeenCalledWith('/api/tasks', {
        params: expect.objectContaining({
          page: 1,
          size: 20,
          keyword: 'test',
          priority: 'HIGH',
          status: 'TODO',
        }),
      })
    })

    it('should omit null/undefined filter params from the request', async () => {
      taskApi = await import('@/api/taskApi')
      const mockInstance = getMockAxiosInstance()
      mockInstance.get.mockResolvedValueOnce({
        data: {
          content: [],
          page: 0,
          size: 20,
          totalElements: 0,
          totalPages: 0,
        },
      })

      await taskApi.fetchTasks({
        page: 0,
        size: 20,
        keyword: '',
        priority: null,
        status: null,
      })

      const callArgs = mockInstance.get.mock.calls[0]
      const params = callArgs[1].params

      // Null/empty filters should be omitted or not sent
      expect(params.priority).toBeUndefined()
      expect(params.status).toBeUndefined()
    })

    it('should return PageResponse data from the response', async () => {
      taskApi = await import('@/api/taskApi')
      const mockInstance = getMockAxiosInstance()

      const mockResponse = {
        data: {
          content: [
            {
              id: 1,
              title: 'Task 1',
              description: 'Desc',
              priority: 'MEDIUM',
              status: 'TODO',
              createdBy: 1,
              createdAt: '2026-03-06T10:00:00',
              updatedAt: null,
            },
          ],
          page: 0,
          size: 20,
          totalElements: 1,
          totalPages: 1,
        },
      }

      mockInstance.get.mockResolvedValueOnce(mockResponse)

      const result = await taskApi.fetchTasks({ page: 0, size: 20 })
      expect(result.content).toHaveLength(1)
      expect(result.page).toBe(0)
      expect(result.totalElements).toBe(1)
    })
  })

  describe('createTask', () => {
    it('should call POST /api/tasks with the task data', async () => {
      taskApi = await import('@/api/taskApi')
      const mockInstance = getMockAxiosInstance()
      mockInstance.post.mockResolvedValueOnce({
        data: {
          id: 1,
          title: 'New Task',
          description: null,
          priority: 'MEDIUM',
          status: 'TODO',
          createdBy: 1,
          createdAt: '2026-03-06T10:00:00',
          updatedAt: null,
        },
      })

      const createData = { title: 'New Task', priority: 'MEDIUM' }
      await taskApi.createTask(createData)

      expect(mockInstance.post).toHaveBeenCalledWith('/api/tasks', createData)
    })

    it('should return the created task from the response', async () => {
      taskApi = await import('@/api/taskApi')
      const mockInstance = getMockAxiosInstance()

      const createdTask = {
        id: 5,
        title: 'Created Task',
        description: 'Desc',
        priority: 'HIGH',
        status: 'TODO',
        createdBy: 1,
        createdAt: '2026-03-06T10:00:00',
        updatedAt: null,
      }

      mockInstance.post.mockResolvedValueOnce({ data: createdTask })

      const result = await taskApi.createTask({ title: 'Created Task', priority: 'HIGH' })
      expect(result.id).toBe(5)
      expect(result.title).toBe('Created Task')
    })
  })

  describe('getTask', () => {
    it('should call GET /api/tasks/:id', async () => {
      taskApi = await import('@/api/taskApi')
      const mockInstance = getMockAxiosInstance()

      const taskData = {
        id: 42,
        title: 'Specific Task',
        description: null,
        priority: 'LOW',
        status: 'IN_PROGRESS',
        createdBy: 1,
        createdAt: '2026-03-06T10:00:00',
        updatedAt: null,
      }

      mockInstance.get.mockResolvedValueOnce({ data: taskData })

      await taskApi.getTask(42)

      expect(mockInstance.get).toHaveBeenCalledWith('/api/tasks/42')
    })

    it('should return the task data from the response', async () => {
      taskApi = await import('@/api/taskApi')
      const mockInstance = getMockAxiosInstance()

      const taskData = {
        id: 42,
        title: 'Specific Task',
        description: 'Details here',
        priority: 'LOW',
        status: 'IN_PROGRESS',
        createdBy: 1,
        createdAt: '2026-03-06T10:00:00',
        updatedAt: '2026-03-06T11:00:00',
      }

      mockInstance.get.mockResolvedValueOnce({ data: taskData })

      const result = await taskApi.getTask(42)
      expect(result.id).toBe(42)
      expect(result.title).toBe('Specific Task')
    })
  })
})

/**
 * T6: M6-Frontend-Infra — Pinia taskStore Tests
 *
 * Tests for src/stores/taskStore.ts:
 * - Initial state values
 * - fetchTasks action: API call, state update, loading/error handling
 * - setKeyword: sets keyword, resets page, calls fetchTasks
 * - setPriorityFilter: sets priorityFilter, resets page, calls fetchTasks
 * - setStatusFilter: sets statusFilter, resets page, calls fetchTasks
 * - setPage: sets page, calls fetchTasks
 * - createTask: calls POST, then refreshes list
 *
 * These tests will fail until the implementation file is created.
 */
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { setActivePinia, createPinia } from 'pinia'
import { useTaskStore } from '@/stores/taskStore'
import * as taskApi from '@/api/taskApi'

// Mock the API module
vi.mock('@/api/taskApi', () => ({
  fetchTasks: vi.fn(),
  createTask: vi.fn(),
  getTask: vi.fn(),
}))

const mockFetchTasks = taskApi.fetchTasks as ReturnType<typeof vi.fn>
const mockCreateTask = taskApi.createTask as ReturnType<typeof vi.fn>

// Helper: build a mock PageResponse
function buildPageResponse(overrides: Record<string, any> = {}) {
  return {
    content: [],
    page: 0,
    size: 20,
    totalElements: 0,
    totalPages: 0,
    ...overrides,
  }
}

// Helper: build a mock Task
function buildTask(overrides: Record<string, any> = {}) {
  return {
    id: 1,
    title: 'Test Task',
    description: null,
    priority: 'MEDIUM',
    status: 'TODO',
    createdBy: 1,
    createdAt: '2026-03-06T10:00:00',
    updatedAt: null,
    ...overrides,
  }
}

describe('taskStore', () => {
  beforeEach(() => {
    setActivePinia(createPinia())
    vi.clearAllMocks()
    mockFetchTasks.mockResolvedValue(buildPageResponse())
  })

  afterEach(() => {
    vi.restoreAllMocks()
  })

  // =============================================
  // Initial State Tests
  // =============================================
  describe('initial state', () => {
    it('should have tasks as empty array', () => {
      const store = useTaskStore()
      expect(store.tasks).toEqual([])
    })

    it('should have page=0', () => {
      const store = useTaskStore()
      expect(store.page).toBe(0)
    })

    it('should have size=20', () => {
      const store = useTaskStore()
      expect(store.size).toBe(20)
    })

    it('should have totalElements=0', () => {
      const store = useTaskStore()
      expect(store.totalElements).toBe(0)
    })

    it('should have totalPages=0', () => {
      const store = useTaskStore()
      expect(store.totalPages).toBe(0)
    })

    it('should have keyword as empty string', () => {
      const store = useTaskStore()
      expect(store.keyword).toBe('')
    })

    it('should have priorityFilter=null', () => {
      const store = useTaskStore()
      expect(store.priorityFilter).toBeNull()
    })

    it('should have statusFilter=null', () => {
      const store = useTaskStore()
      expect(store.statusFilter).toBeNull()
    })

    it('should have loading=false', () => {
      const store = useTaskStore()
      expect(store.loading).toBe(false)
    })

    it('should have error=null', () => {
      const store = useTaskStore()
      expect(store.error).toBeNull()
    })
  })

  // =============================================
  // fetchTasks Action Tests
  // =============================================
  describe('fetchTasks', () => {
    it('should call taskApi.fetchTasks with correct query params', async () => {
      const store = useTaskStore()
      await store.fetchTasks()

      expect(mockFetchTasks).toHaveBeenCalledWith(
        expect.objectContaining({
          page: 0,
          size: 20,
        })
      )
    })

    it('should pass keyword when set', async () => {
      const store = useTaskStore()
      store.keyword = 'search-term'
      await store.fetchTasks()

      expect(mockFetchTasks).toHaveBeenCalledWith(
        expect.objectContaining({
          keyword: 'search-term',
        })
      )
    })

    it('should pass priorityFilter when set', async () => {
      const store = useTaskStore()
      store.priorityFilter = 'HIGH'
      await store.fetchTasks()

      expect(mockFetchTasks).toHaveBeenCalledWith(
        expect.objectContaining({
          priority: 'HIGH',
        })
      )
    })

    it('should pass statusFilter when set', async () => {
      const store = useTaskStore()
      store.statusFilter = 'TODO'
      await store.fetchTasks()

      expect(mockFetchTasks).toHaveBeenCalledWith(
        expect.objectContaining({
          status: 'TODO',
        })
      )
    })

    it('should update state with response data', async () => {
      const tasks = [buildTask({ id: 1 }), buildTask({ id: 2, title: 'Task 2' })]
      mockFetchTasks.mockResolvedValueOnce(
        buildPageResponse({
          content: tasks,
          page: 0,
          size: 20,
          totalElements: 50,
          totalPages: 3,
        })
      )

      const store = useTaskStore()
      await store.fetchTasks()

      expect(store.tasks).toHaveLength(2)
      expect(store.tasks[0].id).toBe(1)
      expect(store.tasks[1].id).toBe(2)
      expect(store.totalElements).toBe(50)
      expect(store.totalPages).toBe(3)
    })

    it('should set loading=true before the request starts', async () => {
      let loadingDuringRequest = false

      mockFetchTasks.mockImplementationOnce(async () => {
        // At the time the API is called, loading should be true
        // We capture this via a closure over the store
        loadingDuringRequest = true
        return buildPageResponse()
      })

      const store = useTaskStore()

      // Spy on the loading state change by checking it inside the mock
      const originalFetchTasks = mockFetchTasks
      mockFetchTasks.mockImplementationOnce(async () => {
        // Check that loading is true during the API call
        loadingDuringRequest = store.loading
        return buildPageResponse()
      })

      await store.fetchTasks()

      expect(loadingDuringRequest).toBe(true)
    })

    it('should set loading=false after the request completes successfully', async () => {
      mockFetchTasks.mockResolvedValueOnce(buildPageResponse())

      const store = useTaskStore()
      await store.fetchTasks()

      expect(store.loading).toBe(false)
    })

    it('should set loading=false after the request fails', async () => {
      mockFetchTasks.mockRejectedValueOnce(new Error('Network error'))

      const store = useTaskStore()

      // fetchTasks should handle the error internally
      await store.fetchTasks()

      expect(store.loading).toBe(false)
    })

    it('should set error message on API failure', async () => {
      mockFetchTasks.mockRejectedValueOnce(new Error('Network error'))

      const store = useTaskStore()
      await store.fetchTasks()

      expect(store.error).toBeTruthy()
      expect(typeof store.error).toBe('string')
    })

    it('should clear error on successful fetch', async () => {
      const store = useTaskStore()

      // First: cause an error
      mockFetchTasks.mockRejectedValueOnce(new Error('fail'))
      await store.fetchTasks()
      expect(store.error).toBeTruthy()

      // Second: successful fetch should clear the error
      mockFetchTasks.mockResolvedValueOnce(buildPageResponse())
      await store.fetchTasks()
      expect(store.error).toBeNull()
    })
  })

  // =============================================
  // setKeyword Action Tests
  // =============================================
  describe('setKeyword', () => {
    it('should set the keyword value', async () => {
      const store = useTaskStore()
      await store.setKeyword('hello')

      expect(store.keyword).toBe('hello')
    })

    it('should reset page to 0', async () => {
      const store = useTaskStore()
      store.page = 5
      await store.setKeyword('search')

      expect(store.page).toBe(0)
    })

    it('should call fetchTasks after setting keyword', async () => {
      const store = useTaskStore()
      await store.setKeyword('test')

      expect(mockFetchTasks).toHaveBeenCalled()
    })

    it('should handle empty keyword (boundary)', async () => {
      const store = useTaskStore()
      store.keyword = 'previous'
      await store.setKeyword('')

      expect(store.keyword).toBe('')
      expect(mockFetchTasks).toHaveBeenCalled()
    })
  })

  // =============================================
  // setPriorityFilter Action Tests
  // =============================================
  describe('setPriorityFilter', () => {
    it('should set the priorityFilter value', async () => {
      const store = useTaskStore()
      await store.setPriorityFilter('HIGH')

      expect(store.priorityFilter).toBe('HIGH')
    })

    it('should reset page to 0', async () => {
      const store = useTaskStore()
      store.page = 3
      await store.setPriorityFilter('LOW')

      expect(store.page).toBe(0)
    })

    it('should call fetchTasks after setting filter', async () => {
      const store = useTaskStore()
      await store.setPriorityFilter('MEDIUM')

      expect(mockFetchTasks).toHaveBeenCalled()
    })

    it('should handle null filter (clear filter / boundary)', async () => {
      const store = useTaskStore()
      store.priorityFilter = 'HIGH'
      await store.setPriorityFilter(null)

      expect(store.priorityFilter).toBeNull()
      expect(mockFetchTasks).toHaveBeenCalled()
    })
  })

  // =============================================
  // setStatusFilter Action Tests
  // =============================================
  describe('setStatusFilter', () => {
    it('should set the statusFilter value', async () => {
      const store = useTaskStore()
      await store.setStatusFilter('IN_PROGRESS')

      expect(store.statusFilter).toBe('IN_PROGRESS')
    })

    it('should reset page to 0', async () => {
      const store = useTaskStore()
      store.page = 2
      await store.setStatusFilter('DONE')

      expect(store.page).toBe(0)
    })

    it('should call fetchTasks after setting filter', async () => {
      const store = useTaskStore()
      await store.setStatusFilter('CLOSED')

      expect(mockFetchTasks).toHaveBeenCalled()
    })

    it('should handle null filter (clear filter / boundary)', async () => {
      const store = useTaskStore()
      store.statusFilter = 'TODO'
      await store.setStatusFilter(null)

      expect(store.statusFilter).toBeNull()
      expect(mockFetchTasks).toHaveBeenCalled()
    })
  })

  // =============================================
  // setPage Action Tests
  // =============================================
  describe('setPage', () => {
    it('should set the page value', async () => {
      const store = useTaskStore()
      await store.setPage(3)

      expect(store.page).toBe(3)
    })

    it('should call fetchTasks after setting page', async () => {
      const store = useTaskStore()
      await store.setPage(1)

      expect(mockFetchTasks).toHaveBeenCalled()
    })

    it('should handle page=0 (boundary: first page)', async () => {
      const store = useTaskStore()
      store.page = 5
      await store.setPage(0)

      expect(store.page).toBe(0)
      expect(mockFetchTasks).toHaveBeenCalled()
    })
  })

  // =============================================
  // createTask Action Tests
  // =============================================
  describe('createTask', () => {
    it('should call taskApi.createTask with the provided data', async () => {
      mockCreateTask.mockResolvedValueOnce(buildTask())

      const store = useTaskStore()
      const data = { title: 'New Task', description: 'Desc', priority: 'HIGH' }
      await store.createTask(data)

      expect(mockCreateTask).toHaveBeenCalledWith(data)
    })

    it('should call fetchTasks after successful creation to refresh list', async () => {
      mockCreateTask.mockResolvedValueOnce(buildTask())

      const store = useTaskStore()
      await store.createTask({ title: 'New Task' })

      // fetchTasks should have been called at least once after creation
      expect(mockFetchTasks).toHaveBeenCalled()
    })

    it('should propagate error if createTask API fails', async () => {
      mockCreateTask.mockRejectedValueOnce(new Error('Create failed'))

      const store = useTaskStore()

      await expect(store.createTask({ title: 'Fail Task' })).rejects.toThrow()
    })
  })

  // =============================================
  // Contract Tests: Combined filter params
  // =============================================
  describe('contract: combined filters', () => {
    it('should send all active filters in a single fetchTasks call', async () => {
      const store = useTaskStore()
      store.keyword = 'deploy'
      store.priorityFilter = 'HIGH'
      store.statusFilter = 'IN_PROGRESS'
      store.page = 2
      store.size = 20

      await store.fetchTasks()

      expect(mockFetchTasks).toHaveBeenCalledWith(
        expect.objectContaining({
          page: 2,
          size: 20,
          keyword: 'deploy',
          priority: 'HIGH',
          status: 'IN_PROGRESS',
        })
      )
    })
  })

  // =============================================
  // Error Case Tests
  // =============================================
  describe('error cases', () => {
    it('should handle network error gracefully', async () => {
      mockFetchTasks.mockRejectedValueOnce(new TypeError('Failed to fetch'))

      const store = useTaskStore()
      await store.fetchTasks()

      expect(store.error).toBeTruthy()
      expect(store.loading).toBe(false)
      // tasks should remain unchanged (empty from initial)
      expect(store.tasks).toEqual([])
    })

